#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }

    vector<vector<long long>> dp(n + 1, vector<long long>(k + 1, 0));
